import React, { useEffect } from 'react';
import $ from 'jquery';
import 'datatables.net';
import 'datatables.net-bs4/css/dataTables.bootstrap4.min.css';
import { useSelector } from 'react-redux';
import { RootState } from '../redux/store';
const MyDataTableComponent: React.FC = () => {
  useEffect(() => {
    $('#myDataTable').DataTable();
  }, []);

  const userData = useSelector((state: RootState) => state.user.userData);
  const userExtraInfo = useSelector(
    (state: RootState) => state.user.userExtraInfo
  );
  console.log(userData);
  console.log(userExtraInfo);

  return (
    <table id="myDataTable" className="table">
      <thead>
        <tr>
          <th>Name</th>
          <th>DOB or Age</th>
          <th>Sex</th>
          <th>Mobile</th>
          <th>ID Type</th>
          <th>ID number</th>
          <th>Address</th>
          <th>State</th>
          <th>Country</th>
          <th>City</th>
          <th>Pin Code</th>
        </tr>
      </thead>
      <tbody>
        <tr>
          <td>{userData.firstName}</td>
          <td>{userData.dob}</td>
          <td>{userData.sex}</td>
          <td>{userData.mobile}</td>
          <td>{userData.idType}</td>
          <td>{userData.id}</td>
          <td>{userExtraInfo.address}</td>
          <td>{userExtraInfo.state}</td>
          <td>{userExtraInfo.country}</td>
          <td>{userExtraInfo.city}</td>
          <td>{userExtraInfo.pinCode}</td>
        </tr>
      </tbody>
    </table>
  );
};

export default MyDataTableComponent;
